using namespace std;

long long solve(std::string s, long long k) {
    int n = s.size();
    vector<int> flips(n + 1, 0);
    int flip = 0;
    long long res = 0;

    for (int i = 0; i < n; ++i) {
        flip ^= flips[i];
        char current = s[i];
        if (flip) {
            current = (current == '0') ? '1' : '0';
        }

        if (current == '0') {
            if (i + k > n) {
                return -1;
            }
            res++;
            flip ^= 1;
            flips[i] ^= 1;
            flips[i + k] ^= 1;
        }
    }

    return res;
}
